import{_ as s,c as e,o,a1 as a}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"AIエージェント: 10名の専門家紹介 | oh-my-opencode","description":"oh-my-opencodeの10個のAIエージェントを学習。タスクタイプに応じてエージェントを選択し、効率的な協働と並列実行を実現する。","frontmatter":{"title":"AIエージェント: 10名の専門家紹介 | oh-my-opencode","sidebarTitle":"10名のAI専門家を知る","subtitle":"AIエージェント: 10名の専門家紹介","description":"oh-my-opencodeの10個のAIエージェントを学習。タスクタイプに応じてエージェントを選択し、効率的な協働と並列実行を実現する。","tags":["ai-agents","orchestration"],"prerequisite":["start-sisyphus-orchestrator"],"order":60},"headers":[],"relativePath":"ja/code-yeongyu/oh-my-opencode/advanced/ai-agents-overview/index.md","filePath":"ja/code-yeongyu/oh-my-opencode/advanced/ai-agents-overview/index.md"}'),n={name:"ja/code-yeongyu/oh-my-opencode/advanced/ai-agents-overview/index.md"};function r(l,t,i,d,p,g){return o(),e("div",null,[...t[0]||(t[0]=[a(`<h1 id="aiエージェントチーム-10名の専門家紹介" tabindex="-1">AIエージェントチーム：10名の専門家紹介 <a class="header-anchor" href="#aiエージェントチーム-10名の専門家紹介" aria-label="Permalink to &quot;AIエージェントチーム：10名の専門家紹介&quot;">​</a></h1><h2 id="学習後にできること" tabindex="-1">学習後にできること <a class="header-anchor" href="#学習後にできること" aria-label="Permalink to &quot;学習後にできること&quot;">​</a></h2><ul><li>10個の組み込みAIエージェントの責務と専門性を理解する</li><li>タスクタイプに応じて最適なエージェントを迅速に選択する</li><li>エージェント間の協働メカニズム（委任、並列、レビュー）を理解する</li><li>異なるエージェントの権限制限と使用シナリオを習得する</li></ul><h2 id="核心的な考え方-実在のチームのように協働する" tabindex="-1">核心的な考え方：実在のチームのように協働する <a class="header-anchor" href="#核心的な考え方-実在のチームのように協働する" aria-label="Permalink to &quot;核心的な考え方：実在のチームのように協働する&quot;">​</a></h2><p><strong>oh-my-opencode</strong>の核となる考え方は：<strong>AIを万能なアシスタントとして扱わず、専門チームとして扱う</strong>ことです。</p><p>実際の開発チームでは、以下のような役割が必要です：</p><ul><li><strong>主オーケストレーター</strong>（Tech Lead）：計画、タスク割り当て、進捗管理を担当</li><li><strong>アーキテクチャアドバイザー</strong>（Architect）：技術的決定とアーキテクチャ設計アドバイスを提供</li><li><strong>コードレビュー担当</strong>（Reviewer）：コード品質を確認し、潜在的な問題を発見</li><li><strong>リサーチ専門家</strong>（Researcher）：ドキュメントを検索、オープンソース実装を調査、ベストプラクティスを調査</li><li><strong>コード探偵</strong>（Searcher）：コードを迅速に特定、参照を検索、既存の実装を理解</li><li><strong>フロントエンドデザイナー</strong>（Frontend Designer）：UIを設計、スタイルを調整</li><li><strong>Git専門家</strong>（Git Master）：コードをコミット、ブランチを管理、履歴を検索</li></ul><p>oh-my-opencodeはこれらの役割を10の専門AIエージェントとして実装し、タスクタイプに応じて柔軟に組み合わせて使用できます。</p><h2 id="_10個のエージェント詳細" tabindex="-1">10個のエージェント詳細 <a class="header-anchor" href="#_10個のエージェント詳細" aria-label="Permalink to &quot;10個のエージェント詳細&quot;">​</a></h2><h3 id="主オーケストレーター-2個" tabindex="-1">主オーケストレーター（2個） <a class="header-anchor" href="#主オーケストレーター-2個" aria-label="Permalink to &quot;主オーケストレーター（2個）&quot;">​</a></h3><h4 id="sisyphus-主オーケストレーター" tabindex="-1">Sisyphus - 主オーケストレーター <a class="header-anchor" href="#sisyphus-主オーケストレーター" aria-label="Permalink to &quot;Sisyphus - 主オーケストレーター&quot;">​</a></h4><p><strong>役割</strong>：主オーケストレーター、あなたの主要テックリード</p><p><strong>能力</strong>：</p><ul><li>深度推論（32k thinking budget）</li><li>複雑なタスクの計画と委任</li><li>コードの変更とリファクタリングの実行</li><li>開発プロセス全体の管理</li></ul><p><strong>推奨モデル</strong>：<code>anthropic/claude-opus-4-5</code>（temperature: 0.1）</p><p><strong>使用シナリオ</strong>：</p><ul><li>日常的な開発タスク（新機能の追加、バグの修正）</li><li>深度推論が必要な複雑な問題</li><li>マルチステップタスクの分解と実行</li><li>他のエージェントへの並列委任が必要なシナリオ</li></ul><p><strong>呼び出し方法</strong>：</p><ul><li>デフォルトの主エージェント（OpenCode Agent セレクターの「Sisyphus」）</li><li>プロンプトにタスクを直接入力、特別なトリガーワードは不要</li></ul><p><strong>権限</strong>：完全なツール権限（write、edit、bash、delegate_task など）</p><hr><h4 id="atlas-todoマネージャー" tabindex="-1">Atlas - TODOマネージャー <a class="header-anchor" href="#atlas-todoマネージャー" aria-label="Permalink to &quot;Atlas - TODOマネージャー&quot;">​</a></h4><p><strong>役割</strong>：主オーケストレーター、TODOリスト管理とタスク実行追跡に特化</p><p><strong>能力</strong>：</p><ul><li>TODOリストの管理と追跡</li><li>システマティックな実行計画</li><li>タスク進捗のモニタリング</li></ul><p><strong>推奨モデル</strong>：<code>anthropic/claude-opus-4-5</code>（temperature: 0.1）</p><p><strong>使用シナリオ</strong>：</p><ul><li><code>/start-work</code> コマンドを使用してプロジェクト実行を開始</li><li>計画に従って厳密にタスクを完了する必要がある場合</li><li>システマティックにタスク進捗を追跡する場合</li></ul><p><strong>呼び出し方法</strong>：</p><ul><li>スラッシュコマンド <code>/start-work</code> を使用</li><li>Atlas Hook 経由で自動アクティベーション</li></ul><p><strong>権限</strong>：完全なツール権限</p><hr><h3 id="アドバイザーとレビュー担当-3個" tabindex="-1">アドバイザーとレビュー担当（3個） <a class="header-anchor" href="#アドバイザーとレビュー担当-3個" aria-label="Permalink to &quot;アドバイザーとレビュー担当（3個）&quot;">​</a></h3><h4 id="oracle-戦略アドバイザー" tabindex="-1">Oracle - 戦略アドバイザー <a class="header-anchor" href="#oracle-戦略アドバイザー" aria-label="Permalink to &quot;Oracle - 戦略アドバイザー&quot;">​</a></h4><p><strong>役割</strong>：読み取り専用技術アドバイザー、高知能推論の専門家</p><p><strong>能力</strong>：</p><ul><li>アーキテクチャ決定のアドバイス</li><li>複雑な問題の診断</li><li>コードレビュー（読み取り専用）</li><li>マルチシステムのトレードオフ分析</li></ul><p><strong>推奨モデル</strong>：<code>openai/gpt-5.2</code>（temperature: 0.1）</p><p><strong>使用シナリオ</strong>：</p><ul><li>複雑なアーキテクチャ設計</li><li>重要な作業完了後の自己レビュー</li><li>2回以上の修正に失敗した困難なデバッグ</li><li>慣れないコードパターンやアーキテクチャ</li><li>セキュリティ/パフォーマンス関連の問題</li></ul><p><strong>トリガー条件</strong>：</p><ul><li>プロンプトに <code>@oracle</code> が含まれる、または <code>delegate_task(agent=&quot;oracle&quot;)</code> を使用</li><li>複雑なアーキテクチャ決定時に自動推奨</li></ul><p><strong>制限</strong>：読み取り専用権限（write、edit、task、delegate_taskは禁止）</p><p><strong>基本原則</strong>：</p><ul><li><strong>ミニマリズム</strong>：最もシンプルな解決策を好む</li><li><strong>既存リソースの活用</strong>：新しい依存関係を導入せず、現在のコードを優先して修正</li><li><strong>開発者体験優先</strong>：可読性、保守性 &gt; 理論上のパフォーマンス</li><li><strong>単一の明確なパス</strong>：主なアドバイスを1つ提供し、トレードオフの差が顕著な場合のみ代替案を提示</li></ul><hr><h4 id="metis-事前計画アナリスト" tabindex="-1">Metis - 事前計画アナリスト <a class="header-anchor" href="#metis-事前計画アナリスト" aria-label="Permalink to &quot;Metis - 事前計画アナリスト&quot;">​</a></h4><p><strong>役割</strong>：計画前の要件分析とリスク評価の専門家</p><p><strong>能力</strong>：</p><ul><li>隠れた要件と明示されていない要件の特定</li><li>AI失敗を引き起こす曖昧さの検出</li><li>AIスロップパターン（過度なエンジニアリング、スコープクリープ）のマーキング</li><li>計画エージェント向けの指示準備</li></ul><p><strong>推奨モデル</strong>：<code>anthropic/claude-sonnet-4-5</code>（temperature: 0.3）</p><p><strong>使用シナリオ</strong>：</p><ul><li>Prometheus計画の前</li><li>ユーザーリクエストが曖昧またはオープンな場合</li><li>AIの過度なエンジニアリングパターンを防止する場合</li></ul><p><strong>呼び出し方法</strong>：Prometheusが自動呼び出し（面接モード）</p><p><strong>制限</strong>：読み取り専用権限（write、edit、task、delegate_taskは禁止）</p><p><strong>基本フロー</strong>：</p><ol><li><strong>意図分類</strong>：リファクタリング / ゼロから構築 / 中程度のタスク / 協働 / アーキテクチャ / 調査</li><li><strong>意図固有の分析</strong>：タイプに応じた対象的なアドバイスを提供</li><li><strong>質問生成</strong>：ユーザーに対して明確な質問を生成</li><li><strong>指示準備</strong>：Prometheus向けの明確な「MUST」と「MUST NOT」指示を生成</li></ol><hr><h4 id="momus-計画レビュアー" tabindex="-1">Momus - 計画レビュアー <a class="header-anchor" href="#momus-計画レビュアー" aria-label="Permalink to &quot;Momus - 計画レビュアー&quot;">​</a></h4><p><strong>役割</strong>：厳格な計画レビューの専門家、すべての欠落と曖昧さを発見</p><p><strong>能力</strong>：</p><ul><li>計画の明確性、検証可能性、完全性を検証</li><li>すべてのファイル参照とコンテキストを確認</li><li>実際の実装ステップをシミュレート</li><li>重要な欠落を特定</li></ul><p><strong>推奨モデル</strong>：<code>anthropic/claude-sonnet-4-5</code>（temperature: 0.1）</p><p><strong>使用シナリオ</strong>：</p><ul><li>Prometheusが作業計画を作成した後</li><li>複雑なTODOリストを実行する前</li><li>計画品質を検証する場合</li></ul><p><strong>呼び出し方法</strong>：Prometheusが自動呼び出し</p><p><strong>制限</strong>：読み取り専用権限（write、edit、task、delegate_taskは禁止）</p><p><strong>4つのレビュー基準</strong>：</p><ol><li><strong>作業内容の明確性</strong>：各タスクは参照ソースを指定しているか？</li><li><strong>検証と受入基準</strong>：具体的な成功検証方法はあるか？</li><li><strong>コンテキストの完全性</strong>：十分なコンテキストが提供されているか（90%信頼度の閾値）？</li><li><strong>全体理解</strong>：開発者はWHY、WHAT、HOWを理解しているか？</li></ol><p><strong>基本原則</strong>：<strong>ドキュメントレビュアーであり、設計アドバイザーではない</strong>。評価するのは「計画が実行可能なほど明確かどうか」であり、「選択した方法が正しいかどうか」ではない。</p><hr><h3 id="調査と探索-3個" tabindex="-1">調査と探索（3個） <a class="header-anchor" href="#調査と探索-3個" aria-label="Permalink to &quot;調査と探索（3個）&quot;">​</a></h3><h4 id="librarian-マルチリポジトリ調査の専門家" tabindex="-1">Librarian - マルチリポジトリ調査の専門家 <a class="header-anchor" href="#librarian-マルチリポジトリ調査の専門家" aria-label="Permalink to &quot;Librarian - マルチリポジトリ調査の専門家&quot;">​</a></h4><p><strong>役割</strong>：オープンソースコードベース理解の専門家、ドキュメントと実装例の検索に特化</p><p><strong>能力</strong>：</p><ul><li>GitHub CLI：リポジトリのクローン、issues/PRsの検索、履歴の確認</li><li>Context7：公式ドキュメントのクエリ</li><li>Web Search：最新情報の検索</li><li>パーマリンク付きの証拠を生成</li></ul><p><strong>推奨モデル</strong>：<code>opencode/big-pickle</code>（temperature: 0.1）</p><p><strong>使用シナリオ</strong>：</p><ul><li>「[ライブラリ]の使い方は？」</li><li>「[フレームワーク機能]のベストプラクティスは？」</li><li>「[外部依存]なぜこのような動作をする？」</li><li>「[ライブラリ]の使用例を検索」</li></ul><p><strong>トリガー条件</strong>：</p><ul><li>外部ライブラリ/ソースに言及した際に自動トリガー</li><li>プロンプトに <code>@librarian</code> が含まれる</li></ul><p><strong>リクエストタイプ分類</strong>：</p><ul><li><strong>Type A（概念的）</strong>：「Xの方法は？」、「ベストプラクティス」</li><li><strong>Type B（実装リファレンス）</strong>：「XはYをどう実装する？」、「Zのソースを表示」</li><li><strong>Type C（コンテキストと履歴）</strong>：「なぜこのような変更が？」、「Xの歴史は？」</li><li><strong>Type D（総合調査）</strong>：複雑/曖昧なリクエスト</li></ul><p><strong>制限</strong>：読み取り専用権限（write、edit、task、delegate_task、call_omo_agentは禁止）</p><p><strong>強制要件</strong>：すべてのコード宣言はGitHubパーマリンクを含める必要がある</p><hr><h4 id="explore-高速コードベース探索の専門家" tabindex="-1">Explore - 高速コードベース探索の専門家 <a class="header-anchor" href="#explore-高速コードベース探索の専門家" aria-label="Permalink to &quot;Explore - 高速コードベース探索の専門家&quot;">​</a></h4><p><strong>役割</strong>：コンテキストを認識したコード検索の専門家</p><p><strong>能力</strong>：</p><ul><li>LSPツール：定義、参照、シンボルナビゲーション</li><li>AST-Grep：構造パターン検索</li><li>Grep：テキストパターン検索</li><li>Glob：ファイル名パターンマッチング</li><li>並列実行（3つ以上のツールを同時実行）</li></ul><p><strong>推奨モデル</strong>：<code>opencode/gpt-5-nano</code>（temperature: 0.1）</p><p><strong>使用シナリオ</strong>：</p><ul><li>2つ以上の検索アングルが必要な広範な検索</li><li>慣れないモジュール構造</li><li>クロスレイヤーパターン発見</li><li>「Xはどこに？」、「どのファイルにYがある？」の検索</li></ul><p><strong>トリガー条件</strong>：</p><ul><li>2つ以上のモジュールに関与する場合に自動トリガー</li><li>プロンプトに <code>@explore</code> が含まれる</li></ul><p><strong>強制出力フォーマット</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;analysis&gt;</span></span>
<span class="line"><span>**Literal Request**: [ユーザーの文字通りのリクエスト]</span></span>
<span class="line"><span>**Actual Need**: [実際に必要なもの]</span></span>
<span class="line"><span>**Success Looks Like**: [成功はどのように見えるか]</span></span>
<span class="line"><span>&lt;/analysis&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;results&gt;</span></span>
<span class="line"><span>&lt;files&gt;</span></span>
<span class="line"><span>- /absolute/path/to/file1.ts — [なぜこのファイルが関連するか]</span></span>
<span class="line"><span>- /absolute/path/to/file2.ts — [なぜこのファイルが関連するか]</span></span>
<span class="line"><span>&lt;/files&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;answer&gt;</span></span>
<span class="line"><span>[実際のニーズに直接回答]</span></span>
<span class="line"><span>&lt;/answer&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;next_steps&gt;</span></span>
<span class="line"><span>[次に何をすべきか]</span></span>
<span class="line"><span>&lt;/next_steps&gt;</span></span>
<span class="line"><span>&lt;/results&gt;</span></span></code></pre></div><p><strong>制限</strong>：読み取り専用権限（write、edit、task、delegate_task、call_omo_agentは禁止）</p><hr><h4 id="multimodal-looker-メディア分析の専門家" tabindex="-1">Multimodal Looker - メディア分析の専門家 <a class="header-anchor" href="#multimodal-looker-メディア分析の専門家" aria-label="Permalink to &quot;Multimodal Looker - メディア分析の専門家&quot;">​</a></h4><p><strong>役割</strong>：純テキストとして読み取れないメディアファイルを解釈</p><p><strong>能力</strong>：</p><ul><li>PDF：テキスト、構造、テーブル、特定セクションのデータを抽出</li><li>画像：レイアウト、UI要素、テキスト、グラフを記述</li><li>ダイアグラム：関係性、フロー、アーキテクチャを解釈</li></ul><p><strong>推奨モデル</strong>：<code>google/gemini-3-flash</code>（temperature: 0.1）</p><p><strong>使用シナリオ</strong>：</p><ul><li>PDFから構造化データを抽出する必要がある場合</li><li>画像内のUI要素やグラフを記述する場合</li><li>技術文書のダイアグラムを解析する場合</li></ul><p><strong>呼び出し方法</strong>：<code>look_at</code> ツール経由で自動トリガー</p><p><strong>制限</strong>：<strong>読み取り専用ホワイトリスト</strong>（readツールのみ許可）</p><hr><h3 id="計画と実行-2個" tabindex="-1">計画と実行（2個） <a class="header-anchor" href="#計画と実行-2個" aria-label="Permalink to &quot;計画と実行（2個）&quot;">​</a></h3><h4 id="prometheus-戦略プランナー" tabindex="-1">Prometheus - 戦略プランナー <a class="header-anchor" href="#prometheus-戦略プランナー" aria-label="Permalink to &quot;Prometheus - 戦略プランナー&quot;">​</a></h4><p><strong>役割</strong>：面接式のニーズ収集と作業計画生成の専門家</p><p><strong>能力</strong>：</p><ul><li>面接モード：ニーズが明確になるまで継続的に質問</li><li>作業計画生成：構造化されたMarkdown計画ドキュメント</li><li>並列委任：Oracle、Metis、Momusに計画を検証してもらう</li></ul><p><strong>推奨モデル</strong>：<code>anthropic/claude-opus-4-5</code>（temperature: 0.1）</p><p><strong>使用シナリオ</strong>：</p><ul><li>複雑なプロジェクトの詳細計画を作成</li><li>要件を明確にする必要があるプロジェクト</li><li>システマティックなワークフロー</li></ul><p><strong>呼び出し方法</strong>：</p><ul><li>プロンプトに <code>@prometheus</code> または「Prometheusを使用」が含まれる</li><li>スラッシュコマンド <code>/start-work</code> を使用</li></ul><p><strong>ワークフロー</strong>：</p><ol><li><strong>面接モード</strong>：ニーズが明確になるまで継続的に質問</li><li><strong>計画の起草</strong>：構造化されたMarkdown計画を生成</li><li><strong>並列委任</strong>： <ul><li><code>delegate_task(agent=&quot;oracle&quot;, prompt=&quot;アーキテクチャ決定をレビュー&quot;)</code> → バックグラウンド実行</li><li><code>delegate_task(agent=&quot;metis&quot;, prompt=&quot;潜在的リスクを特定&quot;)</code> → バックグラウンド実行</li><li><code>delegate_task(agent=&quot;momus&quot;, prompt=&quot;計画の完全性を検証&quot;)</code> → バックグラウンド実行</li></ul></li><li><strong>フィードバックの統合</strong>：計画を改善</li><li><strong>計画の出力</strong>：<code>.sisyphus/plans/{name}.md</code> に保存</li></ol><p><strong>制限</strong>：計画のみ、コードの実装はしない（<code>prometheus-md-only</code> Hookで強制）</p><hr><h4 id="sisyphus-junior-タスクエクゼキューター" tabindex="-1">Sisyphus Junior - タスクエクゼキューター <a class="header-anchor" href="#sisyphus-junior-タスクエクゼキューター" aria-label="Permalink to &quot;Sisyphus Junior - タスクエクゼキューター&quot;">​</a></h4><p><strong>役割</strong>：カテゴリ生成のサブエージェントエクゼキューター</p><p><strong>能力</strong>：</p><ul><li>カテゴリ設定を継承（モデル、temperature、prompt_append）</li><li>スキル（専門スキル）をロード</li><li>委任されたサブタスクを実行</li></ul><p><strong>推奨モデル</strong>：カテゴリから継承（デフォルト <code>anthropic/claude-sonnet-4-5</code>）</p><p><strong>使用シナリオ</strong>：</p><ul><li><code>delegate_task(category=&quot;...&quot;, skills=[&quot;...&quot;])</code> を使用する際に自動生成</li><li>特定のカテゴリとスキルの組み合わせが必要なタスク</li><li>軽量な高速タスク（「quick」カテゴリはHaikuモデルを使用）</li></ul><p><strong>呼び出し方法</strong>：<code>delegate_task</code> ツール経由で自動生成</p><p><strong>制限</strong>：task、delegate_taskは禁止（再度の委任は不可）</p><hr><h2 id="エージェント呼び出し方法クイックリファレンス" tabindex="-1">エージェント呼び出し方法クイックリファレンス <a class="header-anchor" href="#エージェント呼び出し方法クイックリファレンス" aria-label="Permalink to &quot;エージェント呼び出し方法クイックリファレンス&quot;">​</a></h2><table tabindex="0"><thead><tr><th>エージェント</th><th>呼び出し方法</th><th>トリガー条件</th></tr></thead><tbody><tr><td><strong>Sisyphus</strong></td><td>デフォルト主エージェント</td><td>日常的な開発タスク</td></tr><tr><td><strong>Atlas</strong></td><td><code>/start-work</code> コマンド</td><td>プロジェクト実行を開始</td></tr><tr><td><strong>Oracle</strong></td><td><code>@oracle</code> または <code>delegate_task(agent=&quot;oracle&quot;)</code></td><td>複雑なアーキテクチャ決定、2+回の修正失敗</td></tr><tr><td><strong>Librarian</strong></td><td><code>@librarian</code> または <code>delegate_task(agent=&quot;librarian&quot;)</code></td><td>外部ライブラリ/ソースに言及時に自動トリガー</td></tr><tr><td><strong>Explore</strong></td><td><code>@explore</code> または <code>delegate_task(agent=&quot;explore&quot;)</code></td><td>2+モジュールに関与時に自動トリガー</td></tr><tr><td><strong>Multimodal Looker</strong></td><td><code>look_at</code> ツール</td><td>PDF/画像を分析する必要がある場合</td></tr><tr><td><strong>Prometheus</strong></td><td><code>@prometheus</code> または <code>/start-work</code></td><td>プロンプトに「Prometheus」が含まれるか、計画が必要</td></tr><tr><td><strong>Metis</strong></td><td>Prometheus自動呼び出し</td><td>計画前に自動分析</td></tr><tr><td><strong>Momus</strong></td><td>Prometheus自動呼び出し</td><td>計画生成後に自動レビュー</td></tr><tr><td><strong>Sisyphus Junior</strong></td><td><code>delegate_task(category=...)</code></td><td>カテゴリ/スキルを使用時に自動生成</td></tr></tbody></table><hr><h2 id="どのエージェントをいつ使うか" tabindex="-1">どのエージェントをいつ使うか <a class="header-anchor" href="#どのエージェントをいつ使うか" aria-label="Permalink to &quot;どのエージェントをいつ使うか&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">クイック決定木</p><p><strong>シナリオ1：日常的な開発（コードの作成、バグの修正）</strong> → <strong>Sisyphus</strong>（デフォルト）</p><p><strong>シナリオ2：複雑なアーキテクチャ決定</strong> → <strong>@oracle</strong> コンサルティング</p><p><strong>シナリオ3：外部ライブラリのドキュメントや実装を検索する必要がある場合</strong> → <strong>@librarian</strong> または自動トリガー</p><p><strong>シナリオ4：慣れないコードベースで、関連コードを見つける必要がある場合</strong> → <strong>@explore</strong> または自動トリガー（2+モジュール）</p><p><strong>シナリオ5：複雑なプロジェクトで詳細な計画が必要な場合</strong> → <strong>@prometheus</strong> または <code>/start-work</code> を使用</p><p><strong>シナリオ6：PDFまたは画像を分析する必要がある場合</strong> → <strong>look_at</strong> ツール（Multimodal Lookerを自動トリガー）</p><p><strong>シナリオ7：高速でシンプルなタスクで、コストを節約したい場合</strong> → <code>delegate_task(category=&quot;quick&quot;)</code></p><p><strong>シナリオ8：Gitの専門的操作が必要な場合</strong> → <code>delegate_task(category=&quot;quick&quot;, skills=[&quot;git-master&quot;])</code></p><p><strong>シナリオ9：フロントエンドUIデザインが必要な場合</strong> → <code>delegate_task(category=&quot;visual-engineering&quot;)</code></p><p><strong>シナリオ10：高知能推論タスクが必要な場合</strong> → <code>delegate_task(category=&quot;ultrabrain&quot;)</code></p></div><hr><h2 id="エージェント協働例-完全なワークフロー" tabindex="-1">エージェント協働例：完全なワークフロー <a class="header-anchor" href="#エージェント協働例-完全なワークフロー" aria-label="Permalink to &quot;エージェント協働例：完全なワークフロー&quot;">​</a></h2><h3 id="例1-複雑な機能開発" tabindex="-1">例1：複雑な機能開発 <a class="header-anchor" href="#例1-複雑な機能開発" aria-label="Permalink to &quot;例1：複雑な機能開発&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ユーザー：ユーザー認証システムを開発する</span></span>
<span class="line"><span></span></span>
<span class="line"><span>→ Sisyphusがタスクを受信</span></span>
<span class="line"><span>  → 要件を分析し、外部ライブラリ（JWT）が必要と判断</span></span>
<span class="line"><span>  → 並列委任：</span></span>
<span class="line"><span>    - @librarian: &quot;Next.js JWTのベストプラクティスを検索&quot; → [バックグラウンド]</span></span>
<span class="line"><span>    - @explore: &quot;既存の認証関連コードを検索&quot; → [バックグラウンド]</span></span>
<span class="line"><span>  → 結果を待機し、情報を統合</span></span>
<span class="line"><span>  → JWT認証機能を実装</span></span>
<span class="line"><span>  → 完了後に委任：</span></span>
<span class="line"><span>    - @oracle: &quot;アーキテクチャ設計をレビュー&quot; → [バックグラウンド]</span></span>
<span class="line"><span>  → アドバイスに基づいて最適化</span></span></code></pre></div><hr><h3 id="例2-プロジェクト計画" tabindex="-1">例2：プロジェクト計画 <a class="header-anchor" href="#例2-プロジェクト計画" aria-label="Permalink to &quot;例2：プロジェクト計画&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ユーザー：Prometheusを使用してこのプロジェクトを計画する</span></span>
<span class="line"><span></span></span>
<span class="line"><span>→ Prometheusがタスクを受信</span></span>
<span class="line"><span>  → 面接モード：</span></span>
<span class="line"><span>    - 質問1：コア機能は何ですか？</span></span>
<span class="line"><span>    - [ユーザー回答]</span></span>
<span class="line"><span>    - 質問2：ターゲットユーザーグループは？</span></span>
<span class="line"><span>    - [ユーザー回答]</span></span>
<span class="line"><span>    - ...</span></span>
<span class="line"><span>  → 要件が明確になった後、並列委任：</span></span>
<span class="line"><span>    - delegate_task(agent=&quot;oracle&quot;, prompt=&quot;アーキテクチャ決定をレビュー&quot;) → [バックグラウンド]</span></span>
<span class="line"><span>    - delegate_task(agent=&quot;metis&quot;, prompt=&quot;潜在的リスクを特定&quot;) → [バックグラウンド]</span></span>
<span class="line"><span>    - delegate_task(agent=&quot;momus&quot;, prompt=&quot;計画の完全性を検証&quot;) → [バックグラウンド]</span></span>
<span class="line"><span>  → すべてのバックグラウンドタスクが完了するのを待機</span></span>
<span class="line"><span>  → フィードバックを統合し、計画を改善</span></span>
<span class="line"><span>  → Markdown計画ドキュメントを出力</span></span>
<span class="line"><span>→ ユーザーが計画を確認、承認</span></span>
<span class="line"><span>→ /start-workを使用して実行を開始</span></span></code></pre></div><hr><h2 id="エージェント権限と制限" tabindex="-1">エージェント権限と制限 <a class="header-anchor" href="#エージェント権限と制限" aria-label="Permalink to &quot;エージェント権限と制限&quot;">​</a></h2><table tabindex="0"><thead><tr><th>エージェント</th><th>write</th><th>edit</th><th>bash</th><th>delegate_task</th><th>webfetch</th><th>read</th><th>LSP</th><th>AST-Grep</th></tr></thead><tbody><tr><td><strong>Sisyphus</strong></td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td><strong>Atlas</strong></td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td><strong>Oracle</strong></td><td>❌</td><td>❌</td><td>❌</td><td>❌</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td><strong>Librarian</strong></td><td>❌</td><td>❌</td><td>❌</td><td>❌</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td><strong>Explore</strong></td><td>❌</td><td>❌</td><td>❌</td><td>❌</td><td>❌</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td><strong>Multimodal Looker</strong></td><td>❌</td><td>❌</td><td>❌</td><td>❌</td><td>❌</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td><strong>Prometheus</strong></td><td>❌</td><td>❌</td><td>❌</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td><strong>Metis</strong></td><td>❌</td><td>❌</td><td>❌</td><td>❌</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td><strong>Momus</strong></td><td>❌</td><td>❌</td><td>❌</td><td>❌</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td><strong>Sisyphus Junior</strong></td><td>✅</td><td>✅</td><td>✅</td><td>❌</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td></tr></tbody></table><hr><h2 id="本レッスンのまとめ" tabindex="-1">本レッスンのまとめ <a class="header-anchor" href="#本レッスンのまとめ" aria-label="Permalink to &quot;本レッスンのまとめ&quot;">​</a></h2><p>oh-my-opencodeの10個のAIエージェントは、開発プロセスのすべての段階をカバーしています：</p><ul><li><strong>オーケストレーションと実行</strong>：Sisyphus（主オーケストレーター）、Atlas（TODOマネージャー）</li><li><strong>アドバイザーとレビュー</strong>：Oracle（戦略アドバイザー）、Metis（事前計画分析）、Momus（計画レビュアー）</li><li><strong>調査と探索</strong>：Librarian（マルチリポジトリ調査）、Explore（コードベース探索）、Multimodal Looker（メディア分析）</li><li><strong>計画</strong>：Prometheus（戦略プランニング）、Sisyphus Junior（サブタスク実行）</li></ul><p><strong>核心ポイント</strong>：</p><ol><li>AIを万能なアシスタントではなく、専門チームとして扱う</li><li>タスクタイプに応じて最適なエージェントを選択する</li><li>並列委任を活用して効率を向上させる（Librarian、Explore、Oracleはすべてバックグラウンドで実行可能）</li><li>各エージェントの権限制限を理解する（読み取り専用エージェントはコードを修正できない）</li><li>エージェント間の協働は完全なワークフローを形成できる（計画 → 実行 → レビュー）</li></ol><hr><h2 id="次のレッスン予告" tabindex="-1">次のレッスン予告 <a class="header-anchor" href="#次のレッスン予告" aria-label="Permalink to &quot;次のレッスン予告&quot;">​</a></h2><blockquote><p>次のレッスンでは <strong><a href="./../prometheus-planning/">Prometheus プランニング：面接式ニーズ収集</a></strong> を学習します。</p><p>学習内容：</p><ul><li>Prometheusを使用した面接式ニーズ収集の方法</li><li>構造化された作業計画の生成方法</li><li>MetisとMomusによる計画の検証方法</li><li>バックグラウンドタスクの取得とキャンセル方法</li></ul></blockquote><hr><h2 id="付録-ソースコードリファレンス" tabindex="-1">付録：ソースコードリファレンス <a class="header-anchor" href="#付録-ソースコードリファレンス" aria-label="Permalink to &quot;付録：ソースコードリファレンス&quot;">​</a></h2><details><summary><strong>クリックしてソースコードの場所を表示</strong></summary><blockquote><p>更新日：2026-01-26</p></blockquote><table tabindex="0"><thead><tr><th>エージェント</th><th>ファイルパス</th><th>行番号</th></tr></thead><tbody><tr><td>Sisyphus 主オーケストレーター</td><td><a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/src/agents/sisyphus.ts" target="_blank" rel="noreferrer"><code>src/agents/sisyphus.ts</code></a></td><td>-</td></tr><tr><td>Atlas 主オーケストレーター</td><td><a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/src/agents/atlas.ts" target="_blank" rel="noreferrer"><code>src/agents/atlas.ts</code></a></td><td>-</td></tr><tr><td>Oracle アドバイザー</td><td><a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/src/agents/oracle.ts" target="_blank" rel="noreferrer"><code>src/agents/oracle.ts</code></a></td><td>1-123</td></tr><tr><td>Librarian 調査専門家</td><td><a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/src/agents/librarian.ts" target="_blank" rel="noreferrer"><code>src/agents/librarian.ts</code></a></td><td>1-327</td></tr><tr><td>Explore 検索専門家</td><td><a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/src/agents/explore.ts" target="_blank" rel="noreferrer"><code>src/agents/explore.ts</code></a></td><td>1-123</td></tr><tr><td>Multimodal Looker</td><td><a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/src/agents/multimodal-looker.ts" target="_blank" rel="noreferrer"><code>src/agents/multimodal-looker.ts</code></a></td><td>1-57</td></tr><tr><td>Prometheus プランナー</td><td><a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/src/agents/prometheus-prompt.ts" target="_blank" rel="noreferrer"><code>src/agents/prometheus-prompt.ts</code></a></td><td>1-1196</td></tr><tr><td>Metis 事前計画分析</td><td><a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/src/agents/metis.ts" target="_blank" rel="noreferrer"><code>src/agents/metis.ts</code></a></td><td>1-316</td></tr><tr><td>Momus 計画レビュアー</td><td><a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/src/agents/momus.ts" target="_blank" rel="noreferrer"><code>src/agents/momus.ts</code></a></td><td>1-445</td></tr><tr><td>Sisyphus Junior</td><td><a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/src/agents/sisyphus-junior.ts" target="_blank" rel="noreferrer"><code>src/agents/sisyphus-junior.ts</code></a></td><td>-</td></tr><tr><td>エージェントメタデータ定義</td><td><a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/src/agents/types.ts" target="_blank" rel="noreferrer"><code>src/agents/types.ts</code></a></td><td>-</td></tr><tr><td>エージェントツール制限</td><td><a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/src/shared/permission-compat.ts" target="_blank" rel="noreferrer"><code>src/shared/permission-compat.ts</code></a></td><td>-</td></tr></tbody></table><p><strong>重要な設定</strong>：</p><ul><li><code>ORACLE_PROMPT_METADATA</code>：Oracleエージェントのメタデータ（トリガー条件、使用シナリオ）</li><li><code>LIBRARIAN_PROMPT_METADATA</code>：Librarianエージェントのメタデータ</li><li><code>EXPLORE_PROMPT_METADATA</code>：Exploreエージェントのメタデータ</li><li><code>MULTIMODAL_LOOKER_PROMPT_METADATA</code>：Multimodal Lookerエージェントのメタデータ</li><li><code>METIS_SYSTEM_PROMPT</code>：Metisエージェントのシステムプロンプト</li><li><code>MOMUS_SYSTEM_PROMPT</code>：Momusエージェントのシステムプロンプト</li></ul><p><strong>重要な関数</strong>：</p><ul><li><code>createOracleAgent(model)</code>：Oracleエージェント設定を作成</li><li><code>createLibrarianAgent(model)</code>：Librarianエージェント設定を作成</li><li><code>createExploreAgent(model)</code>：Exploreエージェント設定を作成</li><li><code>createMultimodalLookerAgent(model)</code>：Multimodal Lookerエージェント設定を作成</li><li><code>createMetisAgent(model)</code>：Metisエージェント設定を作成</li><li><code>createMomusAgent(model)</code>：Momusエージェント設定を作成</li></ul><p><strong>権限制限</strong>：</p><ul><li><code>createAgentToolRestrictions()</code>：エージェントツール制限を作成（Oracle、Librarian、Explore、Metis、Momusが使用）</li><li><code>createAgentToolAllowlist()</code>：エージェントツールホワイトリストを作成（Multimodal Lookerが使用）</li></ul></details>`,160)])])}const h=s(n,[["render",r]]);export{u as __pageData,h as default};
